191→    ) -> Result<Vec<Contact>> {
192→        let mut sql = format!("{SELECT_CONTACTS} WHERE 1=1");
193→        if stage.is_some() {
194→            sql.push_str(" AND stage = ?");
195→        }
196→        if search.is_some() {
197→            sql.push_str(" AND (name LIKE ? OR email LIKE ? OR phone LIKE ?)");
198→        }
199→        sql.push_str(" ORDER BY updated_at DESC LIMIT ? OFFSET ?");
